// =============================================
// NimaView Engine - Simple 3D Game Engine
// Version 3.0.0 - Stable
// =============================================

const NimaView = (function() {
    'use strict';

    // ==========================================
    // PRIVATE VARIABLES
    // ==========================================
    let canvas, ctx;
    let W, H;

    // ==========================================
    // PUBLIC API
    // ==========================================
    const engine = {
        // --- Game State ---
        state: {
            score: 0,
            lives: 3,
            level: 1,
            coins: 0,
            totalCoins: 10,
            playing: true,
            groundY: 30,
        },

        // --- Camera ---
        camera: {
            x: 0,
            y: 50,
            z: -180,
            rotY: 0,
            distance: 180,
            height: 50,
            smoothness: 0.06,
        },

        // --- Player ---
        player: {
            x: 0,
            y: 50,
            z: 0,
            size: 35,
            color: '#00ccff',
            speed: 130,
            vy: 0,
            gravity: 0.8,
            jumpPower: 14,
            rotY: 0,
            onGround: true,
        },

        // --- Lists ---
        coins: [],
        obstacles: [],
        particles: [],
        grid: [],

        // --- Keys ---
        keys: {},

        // --- Audio ---
        audioCtx: null,

        // ==========================================
        // INIT
        // ==========================================
        init(canvasId) {
            canvas = document.getElementById(canvasId);
            if (!canvas) {
                canvas = document.createElement('canvas');
                canvas.id = canvasId || 'game';
                canvas.width = 1024;
                canvas.height = 680;
                document.body.appendChild(canvas);
            }
            ctx = canvas.getContext('2d');
            W = canvas.width;
            H = canvas.height;

            // Setup audio
            try {
                this.audioCtx = new (window.AudioContext || window.webkitAudioContext)();
            } catch(e) {}

            // Setup controls
            this.setupControls();

            // Start level
            this.startLevel();

            // Start loop
            this.gameLoop();

            console.log('🚀 NimaView Engine v3.0 Loaded!');
            return this;
        },

        // ==========================================
        // CONTROLS
        // ==========================================
        setupControls() {
            const self = this;

            window.addEventListener('keydown', function(e) {
                const key = e.key.toLowerCase();
                self.keys[key] = true;

                // Space = Jump
                if (e.key === ' ' || e.key === 'Space') {
                    e.preventDefault();
                    if (self.state.playing && self.player.onGround) {
                        self.player.vy = self.player.jumpPower;
                        self.player.onGround = false;
                        self.playSound(400, 0.15);
                        self.spawnParticles(
                            self.player.x,
                            self.player.y - 20,
                            self.player.z,
                            15,
                            '#88ddff'
                        );
                    }
                }

                // Shift = Descend
                if (e.key === 'Shift') {
                    e.preventDefault();
                    if (self.state.playing && !self.player.onGround) {
                        self.player.vy = -6;
                    }
                }

                // R = Reset
                if (key === 'r') {
                    self.resetGame();
                }
            });

            window.addEventListener('keyup', function(e) {
                const key = e.key.toLowerCase();
                self.keys[key] = false;
                if (e.key === 'Shift') {
                    if (self.player.vy < -2) self.player.vy = -2;
                }
            });
        },

        // ==========================================
        // AUDIO
        // ==========================================
        playSound(freq, duration = 0.15, type = 'sine', vol = 0.08) {
            if (!this.audioCtx) return;
            try {
                const osc = this.audioCtx.createOscillator();
                const gain = this.audioCtx.createGain();
                osc.type = type;
                osc.frequency.value = freq;
                gain.gain.value = vol;
                gain.gain.exponentialRampToValueAtTime(0.001, this.audioCtx.currentTime + duration);
                osc.connect(gain);
                gain.connect(this.audioCtx.destination);
                osc.start();
                osc.stop(this.audioCtx.currentTime + duration);
            } catch(e) {}
        },

        // ==========================================
        // PARTICLES
        // ==========================================
        spawnParticles(x, y, z, count = 20, color = '#ffd93d') {
            for (let i = 0; i < count; i++) {
                this.particles.push({
                    x, y, z,
                    vx: (Math.random() - 0.5) * 12,
                    vy: (Math.random() - 0.5) * 12 - 4,
                    vz: (Math.random() - 0.5) * 12,
                    life: 20 + Math.random() * 20,
                    maxLife: 40,
                    size: 2 + Math.random() * 5,
                    color: color,
                });
            }
        },

        // ==========================================
        // PROJECTION
        // ==========================================
        project(x, y, z) {
            const cam = this.camera;
            const dist = 580 / (z + cam.z + 0.001);
            return {
                x: W/2 + (x - cam.x) * dist,
                y: H/2 + (y - cam.y) * dist,
                scale: dist,
                depth: z + cam.z
            };
        },

        // ==========================================
        // GRID
        // ==========================================
        createGrid() {
            this.grid = [];
            const size = 8;
            const spacing = 60;
            for (let i = -size; i <= size; i++) {
                this.grid.push({
                    x1: i * spacing, y1: 0, z1: -size * spacing,
                    x2: i * spacing, y2: 0, z2: size * spacing,
                });
                this.grid.push({
                    x1: -size * spacing, y1: 0, z1: i * spacing,
                    x2: size * spacing, y2: 0, z2: i * spacing,
                });
            }
        },

        // ==========================================
        // LEVEL SYSTEM
        // ==========================================
        startLevel() {
            const state = this.state;
            const player = this.player;

            // Reset lists
            this.coins = [];
            this.obstacles = [];
            this.particles = [];

            // Reset state
            state.coins = 0;
            state.totalCoins = 8 + state.level * 2;
            if (state.totalCoins > 25) state.totalCoins = 25;
            state.playing = true;

            // Reset player
            player.x = 0;
            player.y = state.groundY + 20;
            player.z = 0;
            player.vy = 0;
            player.onGround = true;

            // Create grid
            this.createGrid();

            // --- Create coins (orbiting) ---
            const orbitRadius = 150 + state.level * 10;
            for (let i = 0; i < state.totalCoins; i++) {
                const angle = (i / state.totalCoins) * Math.PI * 2;
                const r = orbitRadius + (Math.random() - 0.5) * 20;
                this.coins.push({
                    x: Math.cos(angle) * r,
                    y: state.groundY + 25 + (Math.random() - 0.5) * 30,
                    z: Math.sin(angle) * r,
                    size: 14 + Math.random() * 4,
                    color: '#ffd93d',
                    rotY: Math.random() * 6,
                    orbitAngle: angle,
                    orbitRadius: r,
                    orbitSpeed: 0.3 + Math.random() * 0.2,
                    floatOffset: Math.random() * 100,
                    floatSpeed: 0.5 + Math.random() * 0.4,
                    collected: false,
                });
            }

            // --- Create obstacles ---
            const obsColors = ['#ff6b6b', '#ff9f43', '#a29bfe'];
            for (let i = 0; i < Math.min(state.level, 3); i++) {
                const angle = Math.random() * Math.PI * 2;
                const dist = 90 + Math.random() * 80;
                this.obstacles.push({
                    x: Math.cos(angle) * dist,
                    y: state.groundY + 20 + Math.random() * 25,
                    z: Math.sin(angle) * dist,
                    size: 18 + Math.random() * 12,
                    color: obsColors[i % 3],
                    rotY: Math.random() * 6,
                    floatOffset: Math.random() * 100,
                    floatSpeed: 0.4 + Math.random() * 0.4,
                    type: i % 2 === 0 ? 'pyramid' : 'sphere',
                });
            }

            // Update UI
            this.updateUI();

            console.log(`📍 Level ${state.level} started with ${state.totalCoins} coins`);
        },

        // ==========================================
        // UI UPDATE
        // ==========================================
        updateUI() {
            const state = this.state;
            document.getElementById('scoreDisplay').textContent = state.score;
            document.getElementById('coinDisplay').textContent = state.coins;
            document.getElementById('totalCoins').textContent = state.totalCoins;
            document.getElementById('levelDisplay').textContent = state.level;
            document.getElementById('livesDisplay').textContent = state.lives;
        },

        // ==========================================
        // RESET
        // ==========================================
        resetGame() {
            const state = this.state;
            state.score = 0;
            state.lives = 3;
            state.level = 1;
            state.coins = 0;
            state.playing = true;
            this.particles = [];
            this.camera.x = 0;
            this.camera.z = -this.camera.distance;
            this.startLevel();
            this.playSound(880, 0.2, 'square', 0.06);
            console.log('🔄 Game Reset!');
        },

        // ==========================================
        // COLLECT COIN
        // ==========================================
        collectCoin(coin) {
            if (coin.collected) return;
            coin.collected = true;
            const state = this.state;
            state.coins++;
            state.score += 10 + state.level * 2;
            this.spawnParticles(coin.x, coin.y, coin.z, 25, '#ffd93d');
            this.playSound(880, 0.12);
            setTimeout(() => this.playSound(1100, 0.08), 100);
            this.updateUI();

            if (state.coins >= state.totalCoins) {
                this.levelComplete();
            }
        },

        // ==========================================
        // LEVEL COMPLETE
        // ==========================================
        levelComplete() {
            const state = this.state;
            state.playing = false;
            this.spawnParticles(0, 40, 0, 120, '#ffd93d');
            [523, 659, 784, 1047].forEach((f, i) => {
                setTimeout(() => this.playSound(f, 0.12), i * 100);
            });
            console.log(`🎉 Level ${state.level} complete! Score: ${state.score}`);
            setTimeout(() => {
                state.level++;
                this.startLevel();
            }, 1500);
        },

        // ==========================================
        // LOSE LIFE
        // ==========================================
        loseLife() {
            const state = this.state;
            const player = this.player;
            state.lives--;
            this.spawnParticles(player.x, player.y, player.z, 40, '#ff6b6b');
            this.playSound(200, 0.3, 'sawtooth', 0.06);
            this.updateUI();

            if (state.lives <= 0) {
                state.playing = false;
                this.spawnParticles(0, 40, 0, 200, '#ff6b6b');
                [440, 349, 294].forEach((f, i) => {
                    setTimeout(() => this.playSound(f, 0.3, 'sawtooth', 0.05), i * 200);
                });
                console.log(`💔 Game Over! Final Score: ${state.score}`);
            } else {
                player.x = 0;
                player.y = state.groundY + 20;
                player.z = 0;
                player.vy = 0;
                player.onGround = true;
                console.log(`❤️ ${state.lives} lives remaining`);
            }
        },

        // ==========================================
        // UPDATE
        // ==========================================
        update() {
            const state = this.state;
            const player = this.player;
            const cam = this.camera;

            if (!state.playing) return;

            // --- Player Movement ---
            let moveX = 0, moveZ = 0;
            if (this.keys['w'] || this.keys['arrowup']) moveZ -= 1;
            if (this.keys['s'] || this.keys['arrowdown']) moveZ += 1;
            if (this.keys['a'] || this.keys['arrowleft']) moveX -= 1;
            if (this.keys['d'] || this.keys['arrowright']) moveX += 1;

            if (moveX !== 0 || moveZ !== 0) {
                const len = Math.sqrt(moveX*moveX + moveZ*moveZ);
                moveX /= len;
                moveZ /= len;
                const rot = cam.rotY;
                const cos = Math.cos(rot);
                const sin = Math.sin(rot);
                player.x += (moveX * cos - moveZ * sin) * player.speed * 0.016;
                player.z += (moveX * sin + moveZ * cos) * player.speed * 0.016;
            }

            // --- Gravity ---
            if (!player.onGround) {
                player.vy -= player.gravity;
            }
            player.y += player.vy * 0.1;

            // --- Ground collision ---
            if (player.y <= state.groundY) {
                player.y = state.groundY;
                if (player.vy < 0) {
                    player.vy = 0;
                    player.onGround = true;
                }
            }

            // --- Boundary ---
            const boundary = 320;
            const half = player.size / 2;
            if (player.x < -boundary + half) player.x = -boundary + half;
            if (player.x > boundary - half) player.x = boundary - half;
            if (player.z < -boundary + half) player.z = -boundary + half;
            if (player.z > boundary - half) player.z = boundary - half;

            // --- Fall death ---
            if (player.y < -100) {
                this.loseLife();
            }

            // --- Camera follow ---
            const rot = cam.rotY;
            const cos = Math.cos(rot);
            const sin = Math.sin(rot);
            const behindX = -sin * cam.distance;
            const behindZ = -cos * cam.distance;
            const targetX = player.x + behindX;
            const targetZ = player.z + behindZ;
            cam.x += (targetX - cam.x) * cam.smoothness;
            cam.z += (targetZ - cam.z) * cam.smoothness;
            cam.y += (cam.height - cam.y) * cam.smoothness;

            // --- Player rotation ---
            player.rotY += 0.03;

            // --- Update coins ---
            const time = Date.now() / 1000;
            for (const coin of this.coins) {
                if (coin.collected) continue;
                coin.orbitAngle += coin.orbitSpeed * 0.02;
                const r = coin.orbitRadius;
                const angle = coin.orbitAngle;
                coin.x = Math.cos(angle) * r;
                coin.z = Math.sin(angle) * r;
                coin.y += Math.sin(time * coin.floatSpeed + coin.floatOffset) * 0.03;
                coin.rotY += 0.04;
            }

            // --- Update obstacles ---
            for (const obs of this.obstacles) {
                obs.rotY += 0.006;
                obs.y += Math.sin(time * obs.floatSpeed + obs.floatOffset) * 0.03;
            }

            // --- Coin collision ---
            for (const coin of this.coins) {
                if (coin.collected) continue;
                const dx = player.x - coin.x;
                const dy = player.y - coin.y;
                const dz = player.z - coin.z;
                const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);
                if (dist < (player.size/2 + coin.size/2) * 0.8) {
                    this.collectCoin(coin);
                }
            }

            // --- Obstacle collision ---
            for (const obs of this.obstacles) {
                const dx = player.x - obs.x;
                const dy = player.y - obs.y;
                const dz = player.z - obs.z;
                const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);
                if (dist < (player.size/2 + obs.size/2) * 0.7) {
                    this.loseLife();
                    const angle = Math.atan2(dz, dx);
                    player.x += Math.cos(angle) * 10;
                    player.z += Math.sin(angle) * 10;
                    player.vy = 3;
                    break;
                }
            }

            // --- Update particles ---
            this.particles = this.particles.filter(p => {
                p.x += p.vx * 0.1;
                p.y += p.vy * 0.1;
                p.z += p.vz * 0.1;
                p.vy += 0.2;
                p.life--;
                p.size *= 0.97;
                return p.life > 0 && p.size > 0.3;
            });
        },

        // ==========================================
        // RENDER
        // ==========================================
        render() {
            // --- Clear ---
            const grad = ctx.createRadialGradient(W/2, H/2-50, 50, W/2, H/2, 600);
            grad.addColorStop(0, '#1a0a2e');
            grad.addColorStop(0.5, '#0d0d2b');
            grad.addColorStop(1, '#050510');
            ctx.fillStyle = grad;
            ctx.fillRect(0, 0, W, H);

            // --- Draw Grid ---
            for (const line of this.grid) {
                const p1 = this.project(line.x1, line.y1, line.z1);
                const p2 = this.project(line.x2, line.y2, line.z2);
                ctx.beginPath();
                ctx.moveTo(p1.x, p1.y);
                ctx.lineTo(p2.x, p2.y);
                ctx.strokeStyle = '#223355';
                ctx.lineWidth = 1;
                ctx.stroke();
            }

            // --- Collect all objects for depth sorting ---
            let drawObjects = [];

            // Obstacles
            for (const obs of this.obstacles) {
                drawObjects.push({ type: 'obstacle', obj: obs });
            }

            // Coins
            for (const coin of this.coins) {
                if (coin.collected) continue;
                drawObjects.push({ type: 'coin', obj: coin });
            }

            // Player
            drawObjects.push({ type: 'player', obj: this.player });

            // Sort by depth (far to near)
            const cam = this.camera;
            drawObjects.sort((a, b) => {
                const da = (a.obj.x - cam.x)**2 + (a.obj.y - cam.y)**2 + (a.obj.z - cam.z)**2;
                const db = (b.obj.x - cam.x)**2 + (b.obj.y - cam.y)**2 + (b.obj.z - cam.z)**2;
                return db - da;
            });

            // --- Draw objects ---
            for (const item of drawObjects) {
                const obj = item.obj;
                if (item.type === 'coin') {
                    this.drawCoin(obj);
                } else if (item.type === 'obstacle') {
                    this.drawObstacle(obj);
                } else if (item.type === 'player') {
                    this.drawPlayer(obj);
                }
            }

            // --- Draw particles ---
            for (const p of this.particles) {
                const pos = this.project(p.x, p.y, p.z);
                const size = p.size * pos.scale;
                if (size < 0.3 || pos.depth < 0) continue;
                ctx.globalAlpha = Math.min(1, (p.life / p.maxLife) * 1.2);
                ctx.fillStyle = p.color;
                ctx.shadowColor = p.color;
                ctx.shadowBlur = 10;
                ctx.beginPath();
                ctx.arc(pos.x, pos.y, Math.max(1, size), 0, Math.PI * 2);
                ctx.fill();
                ctx.shadowBlur = 0;
            }
            ctx.globalAlpha = 1;

            // --- Game Over message ---
            if (!this.state.playing && this.state.lives <= 0) {
                ctx.fillStyle = 'rgba(0,0,0,0.5)';
                ctx.fillRect(0, 0, W, H);
                ctx.fillStyle = '#ff6b6b';
                ctx.font = 'bold 60px Arial';
                ctx.textAlign = 'center';
                ctx.fillText('💔 Game Over', W/2, H/2 - 20);
                ctx.fillStyle = '#88ddff';
                ctx.font = '24px Arial';
                ctx.fillText(`امتیاز نهایی: ${this.state.score}`, W/2, H/2 + 50);
                ctx.fillStyle = '#8899bb';
                ctx.font = '18px Arial';
                ctx.fillText('برای شروع مجدد کلید R را بزنید', W/2, H/2 + 100);
            }
        },

        // ==========================================
        // DRAW FUNCTIONS
        // ==========================================
        drawPlayer(obj) {
            const center = this.project(obj.x, obj.y, obj.z);
            const size = obj.size * center.scale;
            if (size < 2 || center.depth < 0) return;

            ctx.shadowColor = '#00ccff';
            ctx.shadowBlur = 25;
            ctx.strokeStyle = '#00ccff';
            ctx.lineWidth = 2.5;
            ctx.strokeRect(center.x - size/2, center.y - size/2, size, size);
            ctx.shadowBlur = 0;
        },

        drawCoin(obj) {
            const center = this.project(obj.x, obj.y, obj.z);
            const radius = obj.size * center.scale * 0.7;
            if (radius < 1 || center.depth < 0) return;

            const grad = ctx.createRadialGradient(
                center.x - radius * 0.2, center.y - radius * 0.3, radius * 0.1,
                center.x, center.y, radius
            );
            grad.addColorStop(0, '#fffbe6');
            grad.addColorStop(0.3, '#ffd93d');
            grad.addColorStop(1, '#b8860b');
            ctx.fillStyle = grad;
            ctx.shadowColor = '#ffd93d';
            ctx.shadowBlur = 20;
            ctx.beginPath();
            ctx.arc(center.x, center.y, Math.max(2, radius), 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 0;
        },

        drawObstacle(obj) {
            const center = this.project(obj.x, obj.y, obj.z);
            const size = obj.size * center.scale;
            if (size < 2 || center.depth < 0) return;

            ctx.strokeStyle = obj.color;
            ctx.lineWidth = 1.5;
            ctx.shadowColor = obj.color;
            ctx.shadowBlur = 10;
            if (obj.type === 'sphere') {
                ctx.beginPath();
                ctx.arc(center.x, center.y, size/2, 0, Math.PI * 2);
                ctx.stroke();
            } else {
                const half = size/2;
                ctx.strokeRect(center.x - half, center.y - half, size, size);
            }
            ctx.shadowBlur = 0;
        },

        // ==========================================
        // GAME LOOP
        // ==========================================
        gameLoop() {
            this.update();
            this.render();
            requestAnimationFrame(() => this.gameLoop());
        }
    };

    return engine;
})();

// =============================================
// EXPOSE TO GLOBAL
// =============================================
window.NimaView = NimaView;

console.log('📦 NimaView Engine v3.0 Ready!');
console.log('💡 Use NimaView.init("canvasId") to start');
